const rendererOverrides = {
  link_open(tokens, idx, options, env, self) {
    const token = tokens[idx]
    token.attrSet('target', '_blank')
    token.attrSet('rel', 'noopener noreferrer nofollow')
    return self.renderToken(tokens, idx, options)
  }
}

